async function main() {
  console.log('365일 부처님말씀 시딩 시작...')

  let inserted = 0
  let skipped = 0

  for (const item of WISDOM_DATA) {
    try {
      await prisma.dailyWisdom.upsert({
        where: { monthDay: item.monthDay },
        update: {
          title: item.title,
          content: item.content,
          source: item.source,
          verse: item.verse ?? null,
        },
        create: {
          monthDay: item.monthDay,
          title: item.title,
          content: item.content,
          source: item.source,
          verse: item.verse ?? null,
        },
      })
      inserted++
    } catch (e) {
      console.error(`Error on ${item.monthDay}:`, e)
      skipped++
    }
  }

  console.log(`완료: ${inserted}일 삽입/업데이트, ${skipped}일 오류`)
  console.log(`총 데이터: ${WISDOM_DATA.length}일`)
}

main().catch(console.error).finally(() => prisma.$disconnect())
